mapper.select:
SELECT a.id, a.org_id, a.clinic_id, c.clinic_name, a.appointment_no, a.patient_id, p.patient_name, p.mobile AS patient_mobile, a.doctor_id, s.staff_name AS doctor_name, a.source_type, a.appointment_type, a.appointment_date, a.start_time, a.end_time, a.treatment_item_name, a.status, a.arrived_at, a.no_show_flag, a.remark FROM appointment a LEFT JOIN patient p ON p.id = a.patient_id LEFT JOIN staff s ON s.id = a.doctor_id LEFT JOIN clinic c ON c.id = a.clinic_id WHERE a.is_deleted = 0 AND a.org_id = #{orgId}
AND a.clinic_id IN
#{clinicId}
AND a.doctor_id = #{staffId}
AND a.appointment_date = #{query.appointmentDate}
AND a.appointment_date >= #{query.dateFrom}
AND a.appointment_date <= #{query.dateTo}
AND a.clinic_id = #{query.clinicId}
AND a.doctor_id = #{query.doctorId}
AND a.status = #{query.status}
AND ( a.appointment_no LIKE CONCAT('%', #{query.keyword}, '%') OR p.patient_name LIKE CONCAT('%', #{query.keyword}, '%') OR p.mobile LIKE CONCAT('%', #{query.keyword}, '%') OR s.staff_name LIKE CONCAT('%', #{query.keyword}, '%') )
ORDER BY a.start_time DESC, a.id DESC

SELECT a.id, a.org_id, a.clinic_id, c.clinic_name, a.appointment_no, a.patient_id, p.patient_name, p.mobile AS patient_mobile, a.doctor_id, s.staff_name AS doctor_name, a.room_id, a.source_type, a.appointment_type, a.appointment_date, a.start_time, a.end_time, a.treatment_item_name, a.status, a.cancel_reason, a.arrived_at, a.no_show_flag, a.remark, q.queue_no, q.queue_status, q.checkin_at AS queue_checkin_at FROM appointment a LEFT JOIN patient p ON p.id = a.patient_id LEFT JOIN staff s ON s.id = a.doctor_id LEFT JOIN clinic c ON c.id = a.clinic_id LEFT JOIN queue_record q ON q.appointment_id = a.id WHERE a.id = #{id} AND a.org_id = #{orgId} AND a.is_deleted = 0
AND a.clinic_id IN
#{clinicId}
AND a.doctor_id = #{staffId}
LIMIT 1
